business_descriptions = {}
for business in businesses:
    business_descriptions[business['business_id']] = business.get('description', '')

# Get review counts per business
review_counts = locals()['var_functions.execute_python:44']['business_review_counts']

# Aggregate review counts by category
category_counts = {}

for business_ref, count in review_counts.items():
    business_id = business_ref.replace('businessref_', 'businessid_')

    if business_id not in business_descriptions:
        continue

    description = business_descriptions[business_id]

    # Extract categories from description
    patterns = [
        r'offers[^.]*services[^:]*in([^\.]+)',
        r'offers[^.]*services[^:]*including[^:]*([^\.]+)',
        r'offers a range of services[^in]*in([^\.]+)',
        r'offers a diverse range of services[^:]*in the fields of([^\.]+)',
        r'category of [\'"]([^\'"]+)[\'"]',
        r'anyone seeking([^\.]+)'
    ]

    all_categories = []

    for pattern in patterns:
        matches = re.findall(pattern, description, re.IGNORECASE)
        for match in matches:
            # Split by commas and 'and'
            if ' and ' in match:
                parts = match.split(' and ')
                for part in parts:
                    all_categories.extend([c.strip() for c in part.split(',') if c.strip()])
            else:
                all_categories.extend([c.strip() for c in match.split(',') if c.strip()])

    # Clean up categories
    cleaned_categories = []
    for cat in all_categories:
        cat = cat.strip()
        # Remove location info
        if cat in ['Saint Petersburg', 'FL', 'Avon', 'IN', 'Tarpon Springs', 'King of Prussia', 'PA', 'Saint Louis', 'MO']:
            continue
        # Skip generic words
        if cat.lower() in ['', 'the', 'and', 'of', 'a']:
            continue

        # Standardize category names
        if cat in ['Candy Stores', 'Specialty Food', 'Food']:
            cleaned_categories.append('Food & Beverages')
        elif cat in ['Internal Medicine', 'Doctors', 'Health & Medical']:
            cleaned_categories.append('Health & Medical')
        elif cat in ['Nail Salons', 'Hair Removal', 'Waxing']:
            cleaned_categories.append('Beauty & Spas')
        elif cat in ['Cosmetics & Beauty Supply', 'Cosmetic Dentists', 'Tanning', 'Teeth Whitening', 
                     'Dentists', 'Shopping', 'Blow Dry/Out Services', 'Spray Tanning', 'Hair Salons']:
            cleaned_categories.extend(['Beauty & Spas'])
        elif cat in ['Restaurants', 'Chinese']:
            cleaned_categories.append('Restaurants')
        else:
            cleaned_categories.append(cat)

    # Remove duplicates
    unique_categories = list(set(cleaned_categories))

    # Add counts to categories
    for category in unique_categories:
        category_counts[category] = category_counts.get(category, 0) + count

# Sort by review count
sorted_categories = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)

# Get top 5
top_5 = sorted_categories[:5]

print('__RESULT__:')
print(json.dumps(top_5))"}
